<script src="<?=base_admin();?>assets/plugins/select2/select2.min.js"></script><script src="https://cdn.jsdelivr.net/npm/sweetalert2@11"></script>
<script>
function pcError(m){$('.isi_warning_delete').text(m||'Payroll Component gagal diproses.');$('.error_data_delete').fadeIn();}
function pcFilters(){return{tgl_awal:$('#filter_tgl_awal').val(),tgl_akhir:$('#filter_tgl_akhir').val(),component_type:$('#filter_component_type').val(),component_category:$('#filter_component_category').val(),payroll_area:$('#filter_payroll_area').val(),employee_group:$('#filter_employee_group').val(),component_status:$('#filter_component_status').val(),keyword:$('#filter_keyword').val()};}
function pcSet(s,v,t){var e=$(s);if(!v){e.val(null).trigger('change');return;}if(!e.find('option[value="'+v+'"]').length)e.append(new Option(t||v,v,true,true));e.val(v).trigger('change');}
function pcAjax(s,act,p,parent){$(s).select2({width:'100%',allowClear:true,placeholder:p,dropdownParent:parent||$(document.body),ajax:{url:'<?=base_admin();?>modul/payroll_component/payroll_component_action.php?act='+act,type:'POST',dataType:'json',delay:250,data:function(q){return{term:q.term||''};},processResults:function(d){return{results:d.results||[]};}}});}
function pcReset(title){$('#form_payroll_component')[0].reset();$('#pc_id').val('');$('#cost_center_code').val(null).trigger('change');$('#component_type').val('EARNING').trigger('change');$('#component_category').val('BASIC_PAY').trigger('change');$('#payroll_area,#employee_group').val('ALL').trigger('change');$('#calculation_method').val('FIXED_AMOUNT').trigger('change');$('#calculation_base').val('NONE').trigger('change');$('#component_status').val('DRAFT').trigger('change');$('#currency').val('IDR').trigger('change');$('#taxable,#recurring,#prorate,#payslip_display,#posting_required').val('Y').trigger('change');$('#bpjs_base,#retroactive_allowed').val('N').trigger('change');$('#debit_credit').val('DEBIT').trigger('change');$('#valid_from').val('<?=$defaultFrom;?>');$('#valid_to').val('<?=$defaultTo;?>');$('#default_amount,#percentage_rate').val(0);$('#sequence_no').val(100);$('#modal_payroll_component .modal-title').text(title||'Create Payroll Component');}
$(function(){if($.fn.datepicker){$('.pc-date,.date-field').datepicker({format:'yyyy-mm-dd',autoclose:true,todayHighlight:true});}if($.fn.select2){$('#filter_component_type,#filter_component_category,#filter_payroll_area,#filter_employee_group,#filter_component_status,#component_type,#component_category,#payroll_area,#employee_group,#calculation_method,#calculation_base,#component_status,#currency,#taxable,#bpjs_base,#recurring,#prorate,#retroactive_allowed,#payslip_display,#posting_required,#debit_credit').select2({width:'100%',allowClear:true});pcAjax('#cost_center_code','cost_center_search','Pilih Cost Center',$('#modal_payroll_component'));}
var dt=$('#dtb_payroll_component').DataTable({bProcessing:true,bServerSide:true,pageLength:25,dom:"<'row'<'col-sm-12'B>>"+"<'row'<'col-sm-6'l><'col-sm-6'f>>"+"<'row'<'col-sm-12'tr>>"+"<'row'<'col-sm-5'i><'col-sm-7'p>>",buttons:[{extend:'collection',text:<?=hr_js('common_export_data', 'Export Data');?>,buttons:['copyHtml5','excelHtml5','csvHtml5','pdfHtml5']}],columnDefs:[{targets:[0,1],orderable:false,searchable:false},{width:'42px',targets:0},{width:'150px',targets:1}],ajax:{url:'<?=base_admin();?>modul/payroll_component/payroll_component_data.php',type:'post',data:function(d){$.extend(d,pcFilters());},dataSrc:function(j){var k=j.kpi||{};$('#kpi_total').text(k.total||0);$('#kpi_active').text(k.active||0);$('#kpi_earning').text(k.earning||0);$('#kpi_deduction').text(k.deduction||0);$('#kpi_tax').text(k.tax||0);$('#kpi_posting').text(k.posting||0);return j.data||[];},error:function(x){console.log(x.responseText);pcError('Data Payroll Component gagal dimuat.');}}});
$('#btn_open_pc').click(function(){pcReset('Create Payroll Component');$('#modal_payroll_component').modal({backdrop:'static',keyboard:false});});$('#btn_filter_pc').click(function(){dt.draw();});$('#filter_keyword').keyup(function(e){if(e.keyCode===13)dt.draw();});$('#btn_reset_pc').click(function(){$('#filter_tgl_awal').val('<?=$defaultFrom;?>');$('#filter_tgl_akhir').val('<?=$defaultTo;?>');$('#filter_component_type,#filter_component_category,#filter_payroll_area,#filter_employee_group,#filter_component_status').val(null).trigger('change');$('#filter_keyword').val('');dt.draw();});$('#btn_export_pc').click(function(){window.location='<?=base_admin();?>modul/payroll_component/payroll_component_action.php?act=export&'+$.param(pcFilters());});$('.hide_alert_notif').click(function(){$('.error_data_delete').hide();});$('#component_code,#wage_type_code,#gl_account_code').on('keyup change',function(){this.value=this.value.toUpperCase();});
$('#form_payroll_component').submit(function(e){e.preventDefault();var b=$(this).find('button[type=submit]');b.prop('disabled',true).html('<i class="fa fa-spinner fa-spin"></i> <?=hr_h('common_saving', 'Saving...');?>');$.post('<?=base_admin();?>modul/payroll_component/payroll_component_action.php?act=save',$(this).serialize(),function(r){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Component');if(r.status==='good'){$('#modal_payroll_component').modal('hide');dt.draw(false);Swal.fire('Saved','Payroll Component berhasil disimpan.','success');}else pcError(r.error_message);},'json').fail(function(x){b.prop('disabled',false).html('<i class="fa fa-save"></i> Save Component');pcError(x.responseText);});});
$(document).on('click','.btn-pc-detail',function(){$.post('<?=base_admin();?>modul/payroll_component/payroll_component_action.php?act=detail',{id:$(this).data('id')},function(h){$('#pc_detail_body').html(h);$('#modal_pc_detail').modal('show');});});
$(document).on('click','.btn-pc-edit',function(){var id=$(this).data('id');$.post('<?=base_admin();?>modul/payroll_component/payroll_component_action.php?act=get',{id:id},function(r){if(r.status!=='good'){pcError(r.error_message);return;}pcReset('Edit Payroll Component');var h=r.data||{};Object.keys(h).forEach(function(k){var el=$('#'+k);if(el.length&&k!=='cost_center_code')el.val(h[k]);});$('#pc_id').val(h.id);pcSet('#cost_center_code',h.cost_center_code,h.cost_center_text);$('#component_type,#component_category,#payroll_area,#employee_group,#calculation_method,#calculation_base,#component_status,#currency,#taxable,#bpjs_base,#recurring,#prorate,#retroactive_allowed,#payslip_display,#posting_required,#debit_credit').trigger('change');$('#modal_payroll_component').modal({backdrop:'static',keyboard:false});},'json');});
$(document).on('click','.btn-pc-status',function(){var id=$(this).data('id'),status=$(this).data('status');$.post('<?=base_admin();?>modul/payroll_component/payroll_component_action.php?act=status',{id:id,status:status},function(r){if(r.status==='good'){dt.draw(false);Swal.fire('Updated','Status berhasil diubah.','success');}else pcError(r.error_message);},'json');});
$(document).on('click','.btn-pc-delete',function(){if($(this).is(':disabled'))return;var id=$(this).data('id'),no=$(this).data('no');Swal.fire({title:erpLang('confirm_delete_title','Delete Confirmation'),text:no,icon:'warning',showCancelButton:true,confirmButtonText:erpLang('common_delete','Delete'),cancelButtonText:erpLang('common_cancel','Cancel')}).then(function(x){if(!x.isConfirmed)return;$.post('<?=base_admin();?>modul/payroll_component/payroll_component_action.php?act=delete',{id:id},function(r){if(r.status==='good'){dt.draw(false);Swal.fire(erpLang('common_deleted','Deleted'),erpLang('common_deleted_message','Data deleted successfully.'),'success');}else pcError(r.error_message);},'json').fail(function(x){pcError(x.responseText);});});});
});
</script>
